parameters.functionCode:
const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

// Poll for latest signal file
const wsf_dir = path.join(process.env.PCA_ROOT, 'external/weak-signal-finder/dataset');

try {
  const files = fs.readdirSync(wsf_dir)
    .filter(f => f.startsWith('signals_') && f.endsWith('.json'))
    .sort()
    .reverse();

  if (files.length === 0) {
    return [{"signal_file": null, "error": "No signal files found"}];
  }

  const latestFile = path.join(wsf_dir, files[0]);
  const signal_data = JSON.parse(fs.readFileSync(latestFile, 'utf-8'));

  return [{"signal_file": files[0], "data": signal_data}];
} catch (error) {
  return [{"error": error.message}];
}

